#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec3 ret3 = texture(sampler_Forest,vUv).xyz;

vec2 uv1 = vUv-.5;
vec2 uv2 = vUv-.5;

vec3 ret1 = texture(sampler_main, vUv) + GetBlur1(vUv)*0;


vec2 hor = vec2 (.001,0);
vec2 ver = vec2 (0,.001);
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);
vec2 dz = vec2 (dx,dy);

uv1 = uv1*0+.3*cos(uv1*1+1.6) - 2*dz;
float dots = clamp01(.01/length(uv1));


ret1 = 0.3*lum(ret1) + dots*22*(ret1*.1);

ret = ret1;

if(ret.x <= .1 && ret.y <= 0.1 && ret.z <= 0.1){
  vec3 ret2 = texture(sampler_main, vUv) + GetBlur1(vUv)*0;
  ret.x = (.1*audioLowSmooth)+(.1*audioLowSmooth)*(sin(vUv.x*25+uTime*1.111));
  ret.y = (.06*audioHighSmooth)+(.06*audioHighSmooth)*(sin(vUv.x*25+uTime*1.433));
  ret.z = (.08*audioMidSmooth)+(.08*audioMidSmooth)*(sin(vUv.x*25+uTime*1.666));
  ret2.x = (.1*audioLow)+(.1*audioLow)*(sin(vUv.y*25+uTime*1.111));
  ret2.y = (.06*audioHigh)+(.06*audioHigh)*(sin(vUv.y*25+uTime*1.433));
  ret2.z = (.08*audioMid)+(.08*audioMid)*(sin(vUv.y*25+uTime*1.666));

  ret = ret*.66;
  ret2 = ret2*.66;

  ret = mix(ret,ret2,ret2*3);

  vec2 hor1 = vec2 (-.001,0);
  vec2 ver1 = vec2 (0,-.001);
  float dx = GetPixel (vUv-hor1) - GetPixel (vUv+hor1);
  float dy = GetPixel (vUv-ver1) - GetPixel (vUv+ver1);
  vec2 dz = vec2 (dx,dy);

  uv2 = uv2*0+.65*cos(uv2.x*1+(1.6+.2*sin(uTime*2.6643)))*cos(uv2.y*1+(1.6+.2*cos(uTime*2.333))) - 2*dz;
  uv2 = uv2*uRms;

  float dots = clamp01(.01/length(uv2));


  ret = 0.3*lum(ret) + dots*22*(ret*.1);

  ret3 = lum(clamp01(ret3))+ret3*(audioLowSmooth*.177);

  ret = mix(ret,ret3,ret);

}


  fragColor = ret;
}
